    }
}

Output:
<pre class="ftui">
<span style="color:#ff0000;font-weight:bold">Bold red</span>
</pre>

#### SVG Export
pub struct SvgExporter {
    font_size: f32,
    cell_width: f32,
    cell_height: f32,
    background: Color,
}

impl SvgExporter {
    pub fn export(&self, buffer: &Buffer, pool: &GraphemePool) -> String {
        // Generate SVG with text elements
        // Position text precisely
        // Handle colors as fill attributes
    }
}

#### Plain Text Export
pub struct TextExporter {
    strip_styles: bool,
    include_ansi: bool,
}

impl TextExporter {
    pub fn export(&self, buffer: &Buffer, pool: &GraphemePool) -> String {
        // strip_styles: just content
        // include_ansi: full ANSI sequences
    }
}

### Frame Capture
pub struct FrameCapture {
    buffer: Buffer,
    pool: GraphemePool,
    timestamp: Instant,
}

impl Frame {
    pub fn capture(&self) -> FrameCapture {
        // Clone current state for export
    }
}

### Session Recording (Optional)
pub struct SessionRecorder {
    frames: Vec<FrameCapture>,
    max_frames: usize,
}

impl SessionRecorder {
    pub fn record(&mut self, frame: &Frame);
    pub fn export_gif(&self) -> Vec<u8>;  // Feature: gif
    pub fn export_asciinema(&self) -> String;  // Feature: asciinema
}

## Tests Required
- [ ] HTML export preserves colors
- [ ] HTML escape special chars
- [ ] SVG dimensions correct
- [ ] SVG text positioning
- [ ] Plain text strips ANSI
- [ ] Wide characters handled
- [ ] Empty buffer exports cleanly

## Acceptance Criteria
- [ ] HTML exporter with CSS
- [ ] SVG exporter with fonts
- [ ] Plain text exporter
- [ ] Frame capture API
- [ ] Optional session recording
